from autogen import UserProxyAgent

ALLOWED_IMPORTS = {"math", "json", "datetime", "collections", "itertools"}

class RestrictedProxy(UserProxyAgent):
    def run_code(self, code, lang, **kwargs):
        if lang == "python":
            # Block any import not in the allowlist
            for line in code.splitlines():
                if line.strip().startswith("import") or line.strip().startswith("from"):
                    pkg = line.split()[1].split(".")[0]
                    if pkg not in ALLOWED_IMPORTS:
                        return 1, f"Blocked: import of '{pkg}' is not allowed.", None
        return super().run_code(code, lang, **kwargs)

safe_proxy = RestrictedProxy(
    "safe_proxy",
    human_input_mode="NEVER",
    code_execution_config={"work_dir": "safe_ws", "use_docker": False},
    is_termination_msg=lambda m: "TERMINATE" in (m.get("content") or ""),
)
